#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long x, y, K;
        scanf("%lld %lld %lld", &x, &y, &K);
        if (x % K == 0 && y % K == 0) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

